        UserDefaults.standard.set(keyData, forKey: identifier)
    }

    private static func retrieveKey(identifier: String) -> SymmetricKey? {
        guard let keyData = UserDefaults.standard.data(forKey: identifier) else { return nil }
        return SymmetricKey(data: keyData)
    }

    static func encrypt<T: Encodable>(_ data: T, using key: SymmetricKey) throws -> Data {
        let encoder = JSONEncoder()
        let plainTextData = try encoder.encode(data)

        let sealedBox = try AES.GCM.seal(plainTextData, using: key)
        guard let combinedData = sealedBox.combined else {
            throw EncryptionError.failedToCombineSealedBox
        }
        return combinedData
    }

    static func decrypt<T: Decodable>(_ encryptedData: Data, using key: SymmetricKey) throws -> T {
        let sealedBox = try AES.GCM.SealedBox(combined: encryptedData)
        let decryptedData = try AES.GCM.open(sealedBox, using: key)

        let decoder = JSONDecoder()
        return try decoder.decode(T.self, from: decryptedData)
    }

    enum EncryptionError: Error {
        case failedToCombineSealedBox
        case keyNotFound
        case decryptionFailed
        case encodingFailed
        case decodingFailed
