        return getAccount(id: id)?.balance
    }

    // MARK: - Transaction Processing

    func deposit(amount: Decimal, toAccountId: UUID, description: String) throws {
        guard amount > 0 else { throw BankingError.invalidAmount }
        guard var account = accounts.first(where: { $0.id == toAccountId }) else { throw BankingError.accountNotFound }

        account.balance += amount
        let transaction = Transaction(type: .deposit, amount: amount, description: description)
        account.transactions.insert(transaction, at: 0) // Add to top

        updateAccount(account)
        saveAccounts()
    }

    func withdraw(amount: Decimal, fromAccountId: UUID, description: String) throws {
        guard amount > 0 else { throw BankingError.invalidAmount }
        guard var account = accounts.first(where: { $0.id == fromAccountId }) else { throw BankingError.accountNotFound }
        guard account.balance >= amount else { throw BankingError.insufficientFunds }

        account.balance -= amount
        let transaction = Transaction(type: .withdrawal, amount: amount, description: description)
        account.transactions.insert(transaction, at: 0)

        updateAccount(account)
        saveAccounts()
    }

    func transfer(amount: Decimal, fromAccountId: UUID, toAccountId: UUID, description: String) throws {
        guard amount > 0 else { throw BankingError.invalidAmount }
        guard fromAccountId != toAccountId else { throw BankingError.sameAccountTransfer }

        guard var fromAccount = accounts.first(where: { $0.id == fromAccountId }) else { throw BankingError.accountNotFound }
        guard var toAccount = accounts.first(where: { $0.id == toAccountId }) else { throw BankingError.accountNotFound }
        guard fromAccount.balance >= amount else { throw BankingError.insufficientFunds }

