        toAccount.balance += amount

        let fromTransaction = Transaction(type: .transfer, amount: amount, description: "Transfer to \(toAccount.name): \(description)", relatedAccountId: toAccountId)
        let toTransaction = Transaction(type: .transfer, amount: amount, description: "Transfer from \(fromAccount.name): \(description)", relatedAccountId: fromAccountId)

        fromAccount.transactions.insert(fromTransaction, at: 0)
        toAccount.transactions.insert(toTransaction, at: 0)

        updateAccount(fromAccount)
        updateAccount(toAccount)
        saveAccounts()
    }

    private func updateAccount(_ updatedAccount: Account) {
        if let index = accounts.firstIndex(where: { $0.id == updatedAccount.id }) {
            accounts[index] = updatedAccount
        }
    }

    // MARK: - Data Persistence (Encrypted)

